internal static ж<bool> update = flag.Bool("update"u8, false, "update golden results for regression test"u8);

public static void TestRegress(ж<testing.T> Ꮡt) {
    ref var t = ref Ꮡt.Value;

    slice<int32> int32s = new int32[]{1, 10, 32, (int32)(1 << (int)(20)), (1 << (int)(20)) + 1, 1000000000, (int32)(1 << (int)(30)), (int32)(2147483648L - 2), (int32)(2147483648L - 1)}.slice();
    slice<uint32> uint32s = new uint32[]{1, 10, 32, ((uint32)1 << (int)(20)), (1 << (int)(20)) + 1, 1000000000, ((uint32)1 << (int)(30)), (uint32)(2147483648L - 2), (uint32)(2147483648L - 1), (uint32)(4294967296L - 2), (uint32)(4294967296L - 1)}.slice();
    slice<int64> int64s = new int64[]{1, 10, 32, ((int64)1 << (int)(20)), (1 << (int)(20)) + 1, 1000000000, ((int64)1 << (int)(30)), 2147483648L - 2, 2147483648L - 1, (nint)1000000000000000000L, 1152921504606846976L, 9223372036854775806L, 9223372036854775807L}.slice();
    slice<uint64> uint64s = new uint64[]{1, 10, 32, ((uint64)1 << (int)(20)), (1 << (int)(20)) + 1, 1000000000, ((uint64)1 << (int)(30)), (uint64)(2147483648L - 2), (uint64)(2147483648L - 1), 1000000000000000000UL, ((uint64)1 << (int)(60)), 9223372036854775806UL, 9223372036854775807UL, 18446744073709551614UL, 18446744073709551615UL}.slice();
    slice<nint> permSizes = new nint[]{0, 1, 5, 8, 9, 10, 16}.slice();
    nint n = reflect.TypeOf(New(new rand.PCGжSource(NewPCG(1, 2)))).NumMethod();
    nint p = 0;
    ref var buf = ref heap(new bytes.Buffer(), out var Ꮡbuf);
    if (update.Value) {
        fmt.Fprintf(new bytes_BufferжWriter(Ꮡbuf), "var regressGolden = []any{\n"u8);
    }
    for (nint i = 0; i < n; i++) {
        if (update.Value && i > 0) {
            fmt.Fprintf(new bytes_BufferжWriter(Ꮡbuf), "\n"u8);
        }
        var r = New(new rand.PCGжSource(NewPCG(1, 2)));
        var rv = reflect.ValueOf(r);
        var m = rv.Type().Method(i);
        var mv = rv.Method(i);
        var mt = mv.Type();
        if (mt.NumOut() == 0) {
            continue;
        }
        for (nint repeat = 0; repeat < 20; repeat++) {
            slice<reflectꓸValue> args = default!;
            @string argstr = default!;
            if (mt.NumIn() == 1) {
                any x = default!;
                var exprᴛ1 = mt.In(0).Kind();
                if (exprᴛ1 == reflect.ΔInt) {
                    do {
                        if (m.Name == "Perm"u8) {
                            x = permSizes[repeat % len(permSizes)];
                            break;
                        }
                        var big = int64s[repeat % len(int64s)];
                        if ((int64)(nint)big != big) {
                            // On 32-bit machine.
                            // Consume an Int64 like on a 64-bit machine,
                            // to keep the golden data the same on different architectures.
                            r.Int64N(big);
                            if (update.Value) {
                                Ꮡt.Fatalf("must run -update on 64-bit machine"u8);
                            }
                            p++;
                            continue;
                        }
                        x = (nint)big;
                    } while (false);
                }
                else if (exprᴛ1 == reflect.ΔUint) {
                    if (m.Name == "Uint"u8) {
                        continue;
                    }
                    var big = uint64s[repeat % len(uint64s)];
                    if ((uint64)(nuint)big != big) {
                        r.Uint64N(big);
                        // what would happen on 64-bit machine, to keep stream in sync
                        if (update.Value) {
                            Ꮡt.Fatalf("must run -update on 64-bit machine"u8);
                        }
                        p++;
                        continue;
                    }
                    x = (nuint)big;
                }
                else if (exprᴛ1 == reflect.Int32) {
                    x = int32s[repeat % len(int32s)];
                }
                else if (exprᴛ1 == reflect.Int64) {
                    x = int64s[repeat % len(int64s)];
                }
                else if (exprᴛ1 == reflect.Uint32) {
                    x = uint32s[repeat % len(uint32s)];
                }
                else if (exprᴛ1 == reflect.Uint64) {
                    x = uint64s[repeat % len(uint64s)];
                }
                else { /* default: */
                    Ꮡt.Fatalf("unexpected argument type for r.%s"u8, m.Name);
                }

                argstr = fmt.Sprint(x);
                args = append(args, reflect.ValueOf(x));
            }
            any @out = default!;
            @out = mv.Call(args)[0].Interface();
            if (m.Name == "Int"u8 || m.Name == "IntN"u8) {
                @out = (int64)(@out._<nint>());
            }
            if (m.Name == "Uint"u8 || m.Name == "UintN"u8) {
                @out = (uint64)(@out._<nuint>());
            }
            if (update.Value){
                @string val = default!;
                var big = (int64)(1152921504606846976L);
                if ((int64)(nint)big != big && (m.Name == "Int"u8 || m.Name == "IntN"u8 || m.Name == "Uint"u8 || m.Name == "UintN"u8)){
                    // 32-bit machine cannot print 64-bit results
                    val = "truncated"u8;
                } else 
                if (reflect.TypeOf(@out).Kind() == reflect.ΔSlice){
                    val = fmt.Sprintf("%#v"u8, @out);
                } else {
                    val = fmt.Sprintf("%T(%v)"u8, @out, @out);
                }
                fmt.Fprintf(new bytes_BufferжWriter(Ꮡbuf), "\t%s, // %s(%s)\n"u8, val, m.Name, argstr);
            } else 
            if (p >= len(regressGolden)){
                Ꮡt.Errorf("r.%s(%s) = %v, missing golden value"u8, m.Name, argstr, @out);
            } else {
                var want = regressGolden[p];
                if (m.Name == "Int"u8) {
                    want = (int64)(nint)((((nuint)(want._<int64>()) << (int)(1)) >> (int)(1)));
                }
                if (m.Name == "Uint"u8) {
                    want = (uint64)(nuint)(want._<uint64>());
                }
                if (!reflect.DeepEqual(@out, want)) {
                    Ꮡt.Errorf("r.%s(%s) = %v, want %v"u8, m.Name, argstr, @out, want);
                }
            }
            p++;
        }
    }
    if (update.Value) {
        replace(Ꮡt, "regress_test.go"u8, buf.Bytes());
    }
}

public static void TestUpdateExample(ж<testing.T> Ꮡt) => func((defer, recover) => {
    ref var t = ref Ꮡt.Value;

    if (!update.Value) {
        Ꮡt.Skip("-update not given");
    }
    var oldStdout = os.Stdout;
    var oldStdoutʗ1 = oldStdout;
    defer(() => {
        os.Stdout = oldStdoutʗ1;
    });
    var (r, w, err) = os.Pipe();
    if (err != default!) {
        Ꮡt.Fatal(err);
    }
    var rʗ1 = r;
    defer(() => rʗ1.Close());
    var wʗ1 = w;
    defer(() => wʗ1.Close());
    var oldStdoutʗ2 = oldStdout;
    var wʗ2 = w;
    goǃ(() => {
        os.Stdout = wʗ2;
        Example_rand();
        os.Stdout = oldStdoutʗ2;
        wʗ2.Close();
    });
    (var @out, err) = io.ReadAll(new os_FileжReader(r));
    if (err != default!) {
        Ꮡt.Fatal(err);
    }
    ref var buf = ref heap(new bytes.Buffer(), out var Ꮡbuf);
    fmt.Fprintf(new bytes_BufferжWriter(Ꮡbuf), "\t// Output:\n"u8);
    foreach (var (_, line) in strings.Split(((@string)@out), "\n"u8)) {
        if (line != ""u8) {
            fmt.Fprintf(new bytes_BufferжWriter(Ꮡbuf), "\t// %s\n"u8, line);
        }
    }
    replace(Ꮡt, "example_test.go"u8, buf.Bytes());
    // Exit so that Example_rand cannot fail.
    fmt.Printf("UPDATED; ignore non-zero exit status\n"u8);
    os.Exit(1);
});

// replace substitutes the definition text from new into the content of file.
// The text in new is of the form
//
//	var whatever = T{
//		...
//	}
//
// Replace searches file for an exact match for the text of the first line,
// finds the closing brace, and then substitutes new for what used to be in the file.
// This lets us update the regressGolden table during go test -update.
internal static void replace(ж<testing.T> Ꮡt, @string @file, slice<byte> @new) {
    var (first, _, _) = bytes.Cut(@new, slice<byte>("\n"u8));
    first = append(append(slice<byte>("\n"u8), first.ꓸꓸꓸ), (byte)((rune)'\n'));
    var (data, err) = os.ReadFile(@file);
    if (err != default!) {
        Ꮡt.Fatal(err);
    }
    nint i = bytes.Index(data, first);
    if (i < 0) {
        Ꮡt.Fatalf("cannot find %q in %s"u8, first, @file);
    }
    nint j = bytes.Index(data[(int)(i + 1)..], slice<byte>("\n}\n"u8));
    if (j < 0) {
        Ꮡt.Fatalf("cannot find end in %s"u8, @file);
    }
    data = append(append(data.slice(-1, i + 1, i + 1), @new.ꓸꓸꓸ), data[(int)(i + 1 + j + 1)..].ꓸꓸꓸ);
    (data, err) = format.Source(data);
    if (err != default!) {
        Ꮡt.Fatal(err);
    }
    {
        var errΔ1 = os.WriteFile(@file, data, 438); if (errΔ1 != default!) {
            Ꮡt.Fatal(errΔ1);
        }
    }
}

